SELECT COUNT(*) AS total_paragraphs
FROM paragraphs
WHERE book_id = 1;

SELECT COUNT(DISTINCT characters_mentioned) AS unique_characters
FROM paragraphs
WHERE paragraph_number = 1;

SELECT mentions
FROM character_book_appearances
WHERE book_id = 1;

SELECT SUM(paragraphs) AS total_paragraphs
FROM character_book_appearances
WHERE book_id = 1 AND character_id = 0;

SELECT COUNT(*) AS female_character_count
FROM characters
WHERE gender = 'Female';

SELECT sentiment, COUNT(*) AS paragraph_count
FROM paragraphs
GROUP BY sentiment;

SELECT COUNT(DISTINCT book_id) AS total_books
FROM character_book_appearances
WHERE character_id = 1;
